import json

notes = {
  'val_di_funes': {
    'en': 'Come in early morning before the tour buses arrive — the church against the Odle peaks in the mist is one of the most beautiful things I know in South Tyrol.',
    'it': 'Vieni di mattina presto, prima che arrivino i pullman — la chiesa con le Odle nella nebbia è una delle cose più belle che conosco in Alto Adige.',
    'de': 'Komm früh morgens, bevor die Reisebusse kommen — die Kirche vor den Geislerspitzen im Morgennebel ist eines der schönsten Bilder, die ich in Südtirol kenne.'
  },
  'hochmuth_tirolo': {
    'en': 'The Muthöfe farms at the top still serve homemade Speck and Käsknödel — sit on the bench, eat slowly, and look at the view. That is the whole point.',
    'it': 'Le malghe Muthöfe in cima servono ancora speck e Käsknödel fatti in casa — siediti sulla panca, mangia lentamente e guarda il panorama. È questo il punto.',
    'de': 'Die Muthöfe oben servieren noch selbstgemachten Speck und Käsknödel — setz dich auf die Bank, iss langsam und schau auf die Aussicht. Das ist der ganze Zweck.'
  },
  'maso_corto': {
    'en': 'This one rewards patience — the lake at the top is that deep, impossible blue that only high-altitude meltwater gives you. Worth every step.',
    'it': 'Questo sentiero ricompensa la pazienza — il lago in cima è di quel blu profondo e impossibile che solo l\'acqua di fusione d\'alta quota può darti. Vale ogni passo.',
    'de': 'Dieser Weg belohnt Geduld — der See oben leuchtet in dem tiefen, unwirklichen Blau, das nur Hochgebirgsschmelzwasser so haben kann. Jeden Schritt wert.'
  },
  'schenna': {
    'en': 'Schenna sits just above Merano — this loop through vineyards and orchards gives you the full South Tyrolean picture: vines, castles, and mountains all at once.',
    'it': 'Scena è proprio sopra Merano — questo anello tra vigneti e frutteti ti dà l\'immagine completa dell\'Alto Adige: viti, castelli e montagne tutto insieme.',
    'de': 'Schenna liegt direkt über Meran — dieser Rundweg durch Weinberge und Obstgärten zeigt dir das volle Südtiroler Bild: Reben, Burgen und Berge auf einmal.'
  },
  'cascada_loop': {
    'en': 'Dorf Tirol is the kind of village that makes you understand why people have been coming here for centuries. The waterfall at the end is a proper reward.',
    'it': 'Dorf Tirol è il tipo di paese che ti fa capire perché la gente viene qui da secoli. La cascata alla fine è una vera ricompensa.',
    'de': 'Dorf Tirol ist das Dorf, das dir erklärt, warum die Menschen seit Jahrhunderten hierher kommen. Der Wasserfall am Ende ist eine echte Belohnung.'
  },
  'Mastaun': {
    'en': 'The Mastaun Alm is the kind of place you want to not tell anyone about — quiet, genuine, with fresh cheese and a view that goes on forever.',
    'it': 'La malga Mastaun è il tipo di posto che vorresti non dire a nessuno — tranquilla, genuina, con formaggio fresco e un panorama che non finisce mai.',
    'de': 'Die Mastaun Alm ist der Ort, den du für dich behalten möchtest — ruhig, echt, mit frischem Käse und einer Aussicht, die nie endet.'
  }
}

with open('data/trails.json', 'r') as f:
    data = json.load(f)

for trail in data['trails']:
    if trail['id'] in notes:
        trail['josephineNote'] = notes[trail['id']]

with open('data/trails.json', 'w') as f:
    json.dump(data, f, indent=2, ensure_ascii=False)

print('Done. Trails updated:', [t['id'] for t in data['trails'] if 'josephineNote' in t])
"

