/* Josephine editorial note callout */
.josephine-note-callout {
  margin-top: 28px;
  padding: 20px 24px;
  background: linear-gradient(
    135deg,
    rgba(212, 165, 116, 0.08) 0%,
    rgba(18, 44, 36, 0.55) 100%
  );
  border: 1px solid rgba(212, 165, 116, 0.30);
  border-left: 3px solid rgba(212, 165, 116, 0.75);
  border-radius: 14px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.25),
    0 0 40px rgba(212, 165, 116, 0.04) inset;
  animation: fadeInUp 0.5s ease 0.2s both;
}

.josephine-note-label {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
}

.josephine-note-icon {
  font-size: 15px;
  filter: drop-shadow(0 0 6px rgba(212, 165, 116, 0.5));
}

.josephine-note-byline {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(212, 165, 116, 0.85);
}

.josephine-note-text {
  font-size: 15px;
  line-height: 1.65;
  color: rgba(255, 255, 255, 0.88);
  font-style: italic;
  margin: 0;
  letter-spacing: 0.01em;
}

@media (max-width: 600px) {
  .josephine-note-callout {
    padding: 16px 18px;
  }

  .josephine-note-text {
    font-size: 14px;
  }
}

@media screen and (max-width: 480px) {
  .detail-container {
    padding: 0 20px;
  }

  .hero-title {
    font-size: 32px;
  }

  .stats-grid {
    grid-template-columns: 1fr;
  }
}

